      at: c.createdAt,
      artifactId: c.target?.artifactId,
      label: `${prefix} [${loc}]: ${c.content.slice(0, 80)}${c.content.length > 80 ? "\u2026" : ""}`,
      payload: { author: c.author, intent: c.intent, content: c.content }
